  /***************************************************************************************************    ____  _   _    _    ____  _____ ____    __        _____ _____ _   _    __  __  ____ ____  __  __    / ___|| | | |  / \  |  _ \| ____|  _ \   \ \      / /_ _|_   _| | | |  |  \/  |/ ___|  _ \|  \/  |   \___ \| |_| | / _ \ | |_) |  _| | | | |   \ \ /\ / / | |  | | | |_| |  | |\/| | |   | |_) | |\/| |    ___) |  _  |/ ___ \|  _ <| |___| |_| |    \ V  V /  | |  | | |  _  |  | |  | | |___|  _ <| |  | |   |____/|_| |_/_/   \_\_| \_\_____|____/      \_/\_/  |___| |_| |_| |_|  |_|  |_|\____|_| \_\_|  |_|                                                                                                      ***************************************************************************************************/  -- =====================================================================================================================================================  -- Author:  Jake Beh  -- Create date: 22 Sep 2017  -- Description:   -- Modified By: Jake Beh  -- Modified Date: 29 Nov 2017  -- Description: Take from Monthly File Update if Patron_new_tmp does not exists.  -- Modified Date: 12 Sep 2019 (Jake)  -- Modified Remarks: Added FIT Tier  -- Modified By: Zhang Yi  -- Desc : add PROFIT_TIER_FINAL  -- Modified Date: 15 Jun 2020 (Zhang Yi)  -- Desc : add One_Time_TProfit  -- Modified Date: 5 May 2022 by cx  -- Desc : REQ0001328  -- Modified Date: 6 May 2022 by cx  -- Desc : INC0004467  -- Modified Date: 13 May 2024 by cx  -- Desc : Refactoring (TIC0007732)  -- Modified Date: 21 May 2024 by cx  -- Desc : Performance tuning, remove PROFIT_TIER_FINAL from SBANALYPRD02.DatamartX.[dbo].PATRONPROFITTIER as it is obsolete (TIC0007792)  -- **Used in Mobile App  -- =====================================================================================================================================================  ALTER PROCEDURE [dbo].[Generic_GetTiers]    -- Add the parameters for the stored procedure here   @REWARDCARDID varchar(20)  AS  BEGIN   -- SET NOCOUNT ON added to prevent extra result sets from   -- interfering with SELECT statements.   SET NOCOUNT ON;     SET @REWARDCARDID = dbo.GetSRCID(@REWARDCARDID)     IF EXISTS(SELECT TOP 1 REWARDCARDID FROM PATRON_NEW_TMP WITH (NOLOCK) WHERE RewardCardId = @REWARDCARDID)    BEGIN     SELECT a.RewardCardId,     ISNULL(a.One_Time_TProfit_Tier, 'N/A') AS One_Time_TProfit_Tier,     ISNULL(a.One_Time_ADT_Tier, 'N/A') AS One_Time_ADT_Tier,     ISNULL(a.One_Time_TDP_Tier, 'N/A') AS One_Time_TDP_Tier,     a.One_Time_TProfit,     ISNULL(dbo.GetFIT(a.RewardCardId, NULL, NULL), 'N/A') AS Fit_Tier,     a.One_Time_TProfit AS PROFIT_TIER_FINAL     FROM PATRON_NEW_TMP a     WHERE a.RewardCardId = @REWARDCARDID    END   ELSE    BEGIN     SELECT RewardCardId,      ISNULL(One_Time_TProfit_Tier, 'N/A') AS One_Time_TProfit_Tier,     ISNULL(One_Time_ADT_Tier, 'N/A') AS One_Time_ADT_Tier,     ISNULL(One_Time_TDP_Tier, 'N/A') AS One_Time_TDP_Tier,     One_Time_TProfit,     ISNULL(dbo.GetFIT(RewardCardId, NULL, NULL), 'N/A') AS Fit_Tier,     PROFIT_TIER_FINAL     FROM MONTHLY_FILE_DAILY_UPDATE (nolock)     WHERE RewardCardId = @REWARDCARDID    END     END